// api/v3/handlers/foo/handler.go
package foo

import (
    "context"
    "net/http"

    v3 "github.com/openmeterio/openmeter/api/v3"
    "github.com/openmeterio/openmeter/api/v3/apierrors"
    "github.com/openmeterio/openmeter/api/v3/render"
    "github.com/openmeterio/openmeter/api/v3/response"
    "github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
)

type ListFoosHandler httptransport.HandlerWithArgs[ListFoosRequest, *v3.FooPagePaginatedResponse, v3.ListFoosParams]

func (h *Handler) ListFoos() ListFoosHandler {
    return httptransport.NewHandlerWithArgs(
        func(ctx context.Context, r *http.Request, params v3.ListFoosParams) (ListFoosRequest, error) {
            ns, err := h.resolveNamespace(ctx)
            if err != nil {
                return ListFoosRequest{}, apierrors.NewBadRequestProblemResponse(ctx, err)
            }
            return ListFoosRequest{Namespace: ns, Page: params.ToPage()}, nil
        },
        func(ctx context.Context, req ListFoosRequest) (*v3.FooPagePaginatedResponse, error) {
            result, err := h.svc.ListFoos(ctx, req)
            if err != nil {
                return nil, err
            }
            return response.PagePaginationResponse(result, toAPIFoo), nil
        },
        func(ctx context.Context, w http.ResponseWriter, resp *v3.FooPagePaginatedResponse) error {
            return render.RenderJSON(w, http.StatusOK, resp)
        },
        httptransport.AppendOptions(
            httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
        ),
    )
}
